PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?raceCount
WHERE {
  wd:Q107555 wdt:P5122 ?season.
  wd:Q334946 wdt:P5123 ?season.
  { 
    SELECT ?season (COUNT(?race) AS ?raceCount)
    WHERE {
      ?season wdt:P1344 ?race.
    }
    GROUP BY ?season
  }
}
ORDER BY ?raceCount
LIMIT 1 OFFSET 2

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?raceCount
WHERE {
  {
    SELECT ?season (COUNT(?race) AS ?raceCount)
    WHERE {
      ?season wdt:P5122 wd:Q107555 .
      ?season wdt:P5123 wd:Q1153621 .
      ?race wdt:P276 ?season .
      ?race wdt:P31 wd:Q7229351 .
    }
    GROUP BY ?season
  }
}
ORDER BY ?raceCount
LIMIT 1 OFFSET 2

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (xsd:integer(?racesCount) AS ?racesCount)
WHERE {
  ?season wdt:P5122 wd:Q107555 ;
          wdt:P5123 wd:Q1053078 ;
          wdt:P1189 ?racesCount .
  FILTER(DATATYPE(?racesCount) = xsd:integer || DATATYPE(?racesCount) = xsd:string)
}
ORDER BY xsd:integer(?racesCount)
LIMIT 1 OFFSET 2

